    html=html.replace(/src="(?:\.\.\/)*assets\/js\/site\.js\?v=(\d+)"/,`src="${prefix}assets/js/site.js?v=$1"`);
    html=html.replace(/window\.__DATA_PATH__="[^"]*";window\.__ROOT__="[^"]*";window\.__ASSET_PREFIX__="[^"]*";/,`window.__DATA_PATH__="${prefix}assets/data/site-content.json";window.__ROOT__="${prefix}";window.__ASSET_PREFIX__="${prefix}";`);
