      html=html.replace(/<title>[^<]*<\/title>/,`<title>${escapeAttr(title)}</title>`);
      html=html.replace(/<link rel="canonical" href="[^"]*">/,`<link rel="canonical" href="${escapeAttr(url)}">`);
      html=replaceOrInsertMeta(html,"description",`<meta name="description" content="${escapeAttr(desc)}">`);
      html=replaceOrInsertMeta(html,"og:title",`<meta property="og:title" content="${escapeAttr(title)}">`);
      html=replaceOrInsertMeta(html,"og:description",`<meta property="og:description" content="${escapeAttr(desc)}">`);
      html=replaceOrInsertMeta(html,"og:url",`<meta property="og:url" content="${escapeAttr(url)}">`);
      html=replaceOrInsertMeta(html,"og:image",`<meta property="og:image" content="${escapeAttr(image)}">`);
      html=replaceOrInsertMeta(html,"twitter:card",`<meta name="twitter:card" content="summary_large_image">`);
      html=replaceOrInsertMeta(html,"twitter:title",`<meta name="twitter:title" content="${escapeAttr(title)}">`);
      html=replaceOrInsertMeta(html,"twitter:description",`<meta name="twitter:description" content="${escapeAttr(desc)}">`);
      html=replaceOrInsertMeta(html,"twitter:image",`<meta name="twitter:image" content="${escapeAttr(image)}">`);
      if(item.robots)html=replaceOrInsertMeta(html,"robots",`<meta name="robots" content="${escapeAttr(item.robots)}">`);else html=html.replace(/\n\s*<meta name="robots" content="[^"]*">/,"");
