  async function generateBrowserVariants(scope="selected"){if(!state.content)return;const photos=scope==="all"?state.content.photos:[photoById(state.selectedPhotoId)].filter(Boolean);if(!photos.length)return showToast("Fotoğraf seçili değil");const failures=[];showToast(`${photos.length} fotoğraf için varyant üretiliyor...`);for(const p of photos){try{await generateBrowserVariantsForPhoto(p);}catch(e){failures.push(`${p.title||p.id}: ${e.message||e}`);}}if(failures.length===photos.length){showToast("Varyant üretimi başarısız: "+failures[0]);return;}setDirty();await saveToDisk();showToast(failures.length?`Varyantlar kısmen üretildi (${failures.length} hata)`:"Görsel varyantları editörde üretildi");render();}
